function ModelDreamFountain:OnDreamFountainInfoReq()--日常经营信息请求
    local pb = LProtoHelper.CreateProto(LProtoIds.DreamFountainInfoReq)
    SendMessage(pb,LProtoIds.DreamFountainInfoReq)
end
function ModelDreamFountain:OnDreamFountainInfoResp(pb)--日常经营信息返回
    local infos = pb.info                           --魔泉信息
    local helpIds = pb.helpIds                      --已帮助列表
    local infoList = {}
    local helpList = {}
    for i, v in ipairs(infos) do
        local info = StructDreamFountainInfo:New()
        info:CreateByPb(v)
        infoList[info.type] = info
    end
    for i, v in ipairs(helpIds) do
        helpList[v] = v
    end
    self._fountainInfoList = infoList
    self._helpList = helpList
    self:OnDreamFountainShowReq()

    local _redGuard = self._redGuard
    if not _redGuard then
        _redGuard = {}
    end
    local lastReceiveTime = 0
    for i, v in pairs(infoList) do
        local lvRef = self:GetDreamFountainPosLvRefByRefId(v.refId)
        if v.lastReceiveTime ~= 0 and v.lastReceiveTime ~= "" and lastReceiveTime == 0 then
            lastReceiveTime = v.lastReceiveTime
        end
        local list = _redGuard[v.type]
        if not list then
            local isRed = true
            if lvRef.nextId == -1 then
                isRed = false
            end
            list = {refId = v.refId,isRed = isRed}
        else
            local refId = list.refId
            if refId ~= v.refId then
                local isRed = true
                if lvRef.nextId == -1 then
                    isRed = false
                end
                list = {refId = v.refId,isRed = isRed}
            end
        end
        _redGuard[v.type] = list
    end
    self._redGuard = _redGuard
    FireEvent(EventNames.ON_DREAM_FOUNTAIN)

    self._receiveCd = true
    if lastReceiveTime and lastReceiveTime ~= 0 then
        if not self._timer then
            self._timer = LxTimer:New()
        else
            self._timer:TimerRemoveByKey("receiveCd")
        end
        local cd = self:GetDreamFountainRefByKey("dreamFountainGetResCD")
        local cd = cd * 60 + 10
        local currTime = GetTimestamp()
        local timespan = currTime - lastReceiveTime/1000 + 5
        if(timespan > 0 and timespan < cd)then
            self._receiveCd = false
            self._timer:TimerCreate("receiveCd", function(...) self:OnCountDown(...) end, cd - timespan, true, 1)
        end
    end
    FireEvent(EventNames.SHOW_DREAM_FOUNTAIN_BUBBLE)
    self:SetStateAnim()
end
function ModelDreamFountain:OnCountDown(key)--冷却计时
    if key == "receiveCd" then
        self._receiveCd = true
        FireEvent(EventNames.SHOW_DREAM_FOUNTAIN_BUBBLE)
    end
end

