function ModelDreamFountain:GetItemInfoList(infoList,type)
    local isMe = not infoList
    local infoList = infoList or self:GetFountainInfoList()
    local list = {}
    local rewards = {}
    for i, v in pairs(infoList) do
        for j, k in ipairs(v.rewardBox) do
            rewards[k.itemId] = k
        end
    end
    local posRef = self:GetDreamFountainPosRef()
    table.sort(posRef,function (a,b)
        return a.sort < b.sort
    end)
    for i, v in ipairs(posRef) do
        if not type or v.refId == type then
            local info = infoList[v.refId]
            local isOpent = info ~= nil
            local itemInfo = {}
            if isOpent then
                itemInfo = self:GetFountainPosItemAndMax(info.refId)
                local lvRef = self:GetDreamFountainPosLvRefByRefId(info.refId)
                local addRef = self:GetHeroAddRefByTypeAndHeorList(info.type,info.heroLists)
                for j, k in ipairs(itemInfo) do
                    k.add = (addRef and addRef.addition or 0) + info.extraRate
                    k.item = rewards[k.refId]
                    k.isOpent = isOpent
                    k.type = info.type
                    k.lv = lvRef.preId
                end
            elseif isMe then
                local lvRef = self:GetDreamFountainPosRefByType(v.refId,1)
                itemInfo = self:GetFountainPosItemAndMax(lvRef.refId)
                for j, k in ipairs(itemInfo) do
                    k.isOpent = isOpent
                    k.type = lvRef.dunType
                    k.lv = lvRef.preId
                end
            end
            table.insert(list,itemInfo)
        end
    end

    local itemList = {}
    for i, v in ipairs(list) do
        for j, k in ipairs(v) do
            table.insert(itemList,k)
        end
    end
    return itemList
end

