function ModelDreamFountain:GetRedHeroAddTypeByRedType(redPointType)
    if redPointType == ModelRedPoint.DREAM_FOUNTAIN_HEROADD_A or redPointType == ModelRedPoint.DREAM_FOUNTAIN_GUARD_A or redPointType == ModelRedPoint.DREAM_FOUNTAIN_FREE_A then
        return 1
    elseif redPointType == ModelRedPoint.DREAM_FOUNTAIN_HEROADD_B or redPointType == ModelRedPoint.DREAM_FOUNTAIN_GUARD_B  or redPointType == ModelRedPoint.DREAM_FOUNTAIN_FREE_B then
        return 2
    elseif redPointType == ModelRedPoint.DREAM_FOUNTAIN_HEROADD_C or redPointType == ModelRedPoint.DREAM_FOUNTAIN_GUARD_C  or redPointType == ModelRedPoint.DREAM_FOUNTAIN_FREE_C then
        return 3
    elseif redPointType == ModelRedPoint.DREAM_FOUNTAIN_HEROADD_D or redPointType == ModelRedPoint.DREAM_FOUNTAIN_GUARD_D  or redPointType == ModelRedPoint.DREAM_FOUNTAIN_FREE_D then
        return 4
    elseif redPointType == ModelRedPoint.DREAM_FOUNTAIN_HEROADD_E or redPointType == ModelRedPoint.DREAM_FOUNTAIN_GUARD_E  or redPointType == ModelRedPoint.DREAM_FOUNTAIN_FREE_E then
        return 5
    end
end

function ModelDreamFountain:DetectionPosFree(type)--是否还有免费次数
    local info = self:GetFountainInfoByType(type)
    if not info then
        return false
    end
    return info.freeCount - info.useFreeCount > 0
end

function ModelDreamFountain:SetDetectionPosGuard(type,bool)
    if not self._redGuard then
        return
    end
    self._redGuard[type].isRed = bool
end

function ModelDreamFountain:DetectionPosGuard(type)--是否可挑战
    local _redGuard = self._redGuard
    if not _redGuard then
        return false
    end
    local list = _redGuard[type]
    if not list then
        return false
    end
    local bool = list.isRed
    if not bool then
        return false
    end
    local info = self:GetFountainInfoByType(type)
    if not info then
        return false
    end
    local lvRef = self:GetDreamFountainPosLvRefByRefId(info.refId)
    local fight = lvRef.fight
    local levLimit = lvRef.levLimit
    local power = gModelPower:GetMaxMainPower()
    local selfLv = gModelPlayer:GetPlayerLv()
    if power >= fight and selfLv >= levLimit then
        return true
    end
    return false
end

function ModelDreamFountain:DetectionPosHeroAdd(type)
    local posIndexs = self:GetHeroAddListPosNil(type)
    return #posIndexs > 0
end

function ModelDreamFountain:GetHeroAddListPosNil(type)
    local info = self:GetFountainInfoByType(type)
    if not info then
        return {}
    end
    local posRef = self:GetDreamFountainPosRefByRefId(type)
    local lvRef = self:GetDreamFountainPosLvRefByRefId(info.refId)
    local heroNum = string.split(posRef.heroNum,"|")
    local heroPosNum = 0
    for i, v in ipairs(heroNum) do
        if lvRef.preId >= tonumber(v)then
            heroPosNum = heroPosNum + 1
        end
    end
    if heroPosNum <= 0 then
        return {}
    end
    local allHero = gModelHero:GetHeroList()
    if table.isempty(allHero)then
        return {}
    end
    local posIndexs = {}
    local otherbattles = {}--上阵英雄id
    local infos = self:GetFountainInfoList()
    for i, v in pairs(infos) do
        if v.heroLists then
            for j, k in ipairs(v.heroLists) do
                local id = k.hero.id
                otherbattles[id] = true
            end
        end
    end
    local isYesHero = false
    for k,v in pairs(allHero) do
        local hero = v:GetServerData()
        if not otherbattles[hero.id] then
            isYesHero = true
            break
        end
    end
    if not isYesHero then
        return {}
    end
    local heroLists = info.heroLists
    if not heroLists then
        return {1}
    end
    local maxPower = 0
    for k,v in pairs(allHero) do
        local hero = v:GetServerData()
        if not otherbattles[hero.id] and hero.fightPower > maxPower then
            maxPower = math.floor(hero.fightPower)
        end
    end
    local heros = {}
    for i, v in ipairs(heroLists) do
        heros[v.index] = v
    end
    for i = 1, heroPosNum do
        local hero = heros[i]
        if not hero then
            table.insert(posIndexs,i)
        else
            local id = hero.hero.id
            local selfHero = allHero[id]
            local fightPower = 0
            if selfHero then
                fightPower = selfHero._fightPower
            else
                fightPower = hero.hero.fightPower
            end
            if fightPower < maxPower then
                table.insert(posIndexs,i)
            end
        end
    end
    --end
    return posIndexs
end

function ModelDreamFountain:SetStateAnim()--设置状态动画
	local mapTheme = gLGameDisplayTheme:GetMapTheme()
    local infoList = self:GetFountainInfoList()
    local typeState = self._typeState or {}
    local _time
    local addMax = gModelGrade:GetPrivilegeEff(41)
    for i, v in pairs(infoList) do
        local posRef = self:GetDreamFountainPosShowRefByRefId(v.type, mapTheme)
        local lvRef = self:GetDreamFountainPosLvRefByRefId(v.refId)
        local stateAnim = string.split(posRef.stateAnim,"|")

        local items = LxDataHelper.ParseItem(lvRef.onHookReward)
        local capacitys = string.split(lvRef.onHookRewardMax,"|")
        local capacity = math.floor(tonumber(capacitys[1]) * (1+addMax))     --容量
        local itemId = items[1].itemId
        local currYield = 0--当前产量
        for j, k in ipairs(v.rewardBox) do
            if itemId == k.itemId then
                currYield = k.count
                break
            end
        end
        local state = 1--动画状态
        local currRate = currYield/capacity--当前产量容量比
        for j, k in ipairs(stateAnim) do
            local anim = string.split(k,"=")
            local rate = tonumber(anim[1])--目标产量容量比
            if currRate >= rate then
                state = j
            end
        end
        typeState[v.type] = state

        local isNext = stateAnim[state + 1]
        if isNext then
            local nextAnim = string.split(stateAnim[state + 1],"=")
            local nextRate = tonumber(nextAnim[1])--下一阶段目标产量容量比
            local nextYield = capacity * nextRate --下一阶段目标产量
            local margin = nextYield - currYield -- 差额
            local addRef = self:GetHeroAddRefByTypeAndHeorList(v.type,v.heroList)
            local addition = addRef and addRef.addition or 0
            local addNum = addition + v.extraRate--总加成
            local rate = items[1].itemNum--生产速率
            local time = margin/(rate + (rate * addNum)) * 3600 --生产时间（秒）
            if not _time or _time > time then
                _time = time
            end
        end
    end
    self._typeState = typeState
    FireEvent(EventNames.SHOW_DREAM_FOUNTAIN_STATEANIM)
    if self._timer and _time then
        self._timer:TimerRemoveByKey("dreamAnimCd")
        self._timer:TimerCreate("dreamAnimCd", function(...) self:OnDreamFountainInfoReq() end, _time, true, 1)
    end
end
----------------------------获取表数据------------------------------------
function ModelDreamFountain:GetDreamFountainRefByKey(key)--获取参数表
    return GameTable.DreamFountainRef[key]
end

function ModelDreamFountain:GetDreamFountainPosRef()--获取资源位置表
    local list = {}
    for i, v in ipairs(GameTable.DreamFountainPosRef) do
        table.insert(list,v)
    end
    return list
end

function ModelDreamFountain:GetDreamFountainPosShowRef(theme)--获取资源位置显示表
    local list = {}
    for i, v in pairs(GameTable.DreamFountainPosShowRef) do
		if v.theme == theme then
			table.insert(list,v)
		end
    end
    return list
end

function ModelDreamFountain:GetDreamFountainPosRefByType(type,lv)
    for i, v in pairs(GameTable.DreamFountainPosLvRef) do
        if v.dunType == type and v.preId == lv then
            return v
        end
    end
end

function ModelDreamFountain:GetDreamFountainPosRefByRefId(refId)--获取资源位置表
    return GameTable.DreamFountainPosRef[refId]
end

function ModelDreamFountain:GetDreamFountainPosShowRefByRefId(posType, theme)--获取资源位置显示表
	local posShowRefId = theme.."_"..posType
    local ref = GameTable.DreamFountainPosShowRef[posShowRefId]
    if not ref then
        printErrorN2("缺少配置",string.format("GameTable.DreamFountainPosShowRef[%s]",posShowRefId))
    end
    return ref
end

function ModelDreamFountain:GetDreamFountainPosLvRefByRefId(refId)--获取资源位置等级表
    return GameTable.DreamFountainPosLvRef[refId]
end

function ModelDreamFountain:GetFountainPosItemAndMax(refId)--获取资源位置等级表奖励数据
    local ref = self:GetDreamFountainPosLvRefByRefId(refId)
    local list = {}
    local addMax = gModelGrade:GetPrivilegeEff(41)
    local onHookReward = string.split(ref.onHookReward,",")
    local onHookRewardMax = string.split(ref.onHookRewardMax,"|")
    for i, v in ipairs(onHookReward) do
        local itemArr = string.split(v,"=")
        local max = math.floor(tonumber(onHookRewardMax[i]) * (1+addMax))
        local item = {
            refId = tonumber(itemArr[2]),--物品id
            max = max,--物品容量
            h = tonumber(itemArr[3]),--物品每小时基础数量
        }
        table.insert(list,item)
    end
    return list
end

function ModelDreamFountain:GetIsUnlockHeroList(refId,tips)--获取是否解锁上阵英雄
    local lvRef = self:GetDreamFountainPosLvRefByRefId(refId)
    local posRef = self:GetDreamFountainPosRefByRefId(lvRef.dunType)
    local heroNum = string.split(posRef.heroNum,"|")
    local lv = lvRef.preId
    if lv >= tonumber(heroNum[1])then
        return true
    end
    if tips then
        GF.ShowMessage(string.replace(ccClientText(19658),ccLngText(posRef.name),heroNum[1]))
    end
    return false
end

function ModelDreamFountain:GetHeroAddRefByTypeAndHeorList(type,heroList)--获取总战力的伙伴加成表
    local power = 0
    if not heroList then
        return nil
    end
    for i, v in ipairs(heroList) do
        power = power + v.hero.fightPower
    end
    local ref = self:GetHeroAddRef(type,power)
    return ref
end

function ModelDreamFountain:GetDreamFountainHeroAddRefByType(type)--获取伙伴加成表
    local list = {}
    for i, v in pairs(GameTable.DreamFountainHeroAddRef) do
        if type == v.type then
            table.insert(list,v)
        end
    end
    table.sort(list,function (a,b)
        return a.refId < b.refId
    end)
    return list
end

function ModelDreamFountain:GetHeroAddRef(type,power)--根据战力读伙伴加成表
    local refs = self:GetDreamFountainHeroAddRefByType(type)
    local ref = nil --可能为空
    for i, v in ipairs(refs) do
        if v.fightNeed <= power then
            ref = v
        else
            break
        end
    end
    return ref
end

function ModelDreamFountain:GetTotalGetTimes()
    local infoList = self:GetFountainInfoList()
    local total = 0
    local freeNum = 0
    local quick = 0
    for k,v in pairs(infoList) do
        freeNum = v.freeCount - v.useFreeCount
        quick  = v.quickCount - v.useQuickCount
        total = total + freeNum + quick
    end

    return total

end

